INSERT INTO public.beach_day_recommendations VALUES ('del-mar-dog-beach', '2026-04-10', 'go', '2026-04-10 16:00:00+00', '2026-04-10 17:00:00+00', '9am–11am', 'go', 'cloudy', 3, 63.4, 3.7, 3.2, 1.1, 0.8, 25, 'quiet', 13, 0, 11, '["clear_skies", "calm_wind", "quiet_beach", "low_uv", "low_tide"]', '[]', '{}', '{"weight_rain": 0.25, "weight_tide": 0.3, "weight_wind": 0.2, "weight_crowd": 0.15, "nogo_wind_speed": 25, "scoring_version": "v1", "caution_wind_speed": 15, "nogo_precip_chance": 70, "caution_tide_height": 3.5, "caution_precip_chance": 40}', 'Friday looks fantastic with low 1.1ft average tides and calm 3.7mph winds under clear skies. Only 3% rain chance and a comfortable 63°F with quiet beach conditions expected. Perfect spring day for you and your pup to enjoy some peaceful ocean time.', '', '', 'The 9am-11am window gives you the lowest tides of the day at 0.8ft, calmest winds, and the quietest beach before crowds arrive later.', '2026-04-11 06:00:00+00', NULL, '2026-04-10', 'America/Los_Angeles', 'v1', '2026-04-09 04:53:01.343+00', '2026-04-09 04:55:11.843597+00');
INSERT INTO public.beach_day_recommendations VALUES ('del-mar-dog-beach', '2026-04-11', 'go', '2026-04-11 19:00:00+00', '2026-04-11 20:00:00+00', '12pm–2pm', 'caution', 'partly_cloudy', 2, 70.1, 11.3, 7.3, 0.2, 0.2, 75, 'dog_party', 5, 5, 14, '["very_low_tide", "clear_skies", "perfect_temp"]', '["dog_party_crowds"]', '{}', '{"weight_rain": 0.25, "weight_tide": 0.3, "weight_wind": 0.2, "weight_crowd": 0.15, "nogo_wind_speed": 25, "scoring_version": "v1", "caution_wind_speed": 15, "nogo_precip_chance": 70, "caution_tide_height": 3.5, "caution_precip_chance": 40}', 'Saturday brings excellent 0.2ft tides and perfect 70°F weather, but expect dog party crowds throughout the day. Only 5 hours offer decent conditions with 14 hours being too challenging. It''s a mixed bag requiring strategic timing.', 'Prepare for dog party crowds during the best window - it''ll be very busy with lots of dogs and owners.', '', 'The 12pm-2pm window offers the day''s lowest 0.2ft tide with manageable 11mph winds and clear skies. While crowds will be intense, the exceptional beach conditions make it worth navigating the dog party scene.', '2026-04-12 06:00:00+00', NULL, '2026-04-11', 'America/Los_Angeles', 'v1', '2026-04-09 04:53:01.343+00', '2026-04-09 04:55:11.843597+00');
INSERT INTO public.beach_day_recommendations VALUES ('del-mar-dog-beach', '2026-04-12', 'go', '2026-04-13 01:00:00+00', '2026-04-13 02:00:00+00', '6pm–8pm', 'caution', 'sunny', 0, 61.5, 9, 1.2, 3.6, 3.4, 30, 'quiet', 1, 2, 21, '["low_uv", "quiet_beach"]', '["high_tide"]', '{}', '{"weight_rain": 0.25, "weight_tide": 0.3, "weight_wind": 0.2, "weight_crowd": 0.15, "nogo_wind_speed": 25, "scoring_version": "v1", "caution_wind_speed": 15, "nogo_precip_chance": 70, "caution_tide_height": 3.5, "caution_precip_chance": 40}', 'High tides around 3.6ft will limit beach space for most of the day, with only one small window of decent conditions. Temperatures stay cool at 61°F with light 9mph winds and a 24% chance of rain. It''s a challenging day that requires careful timing.', 'High tide will significantly reduce the available beach area for dogs to run and play.', '', 'The 6pm-8pm window offers the day''s most manageable conditions with moderate crowds, low UV, and the tide at its lowest point of 3.4ft, though beach space will still be limited.', '2026-04-13 06:00:00+00', NULL, '2026-04-12', 'America/Los_Angeles', 'v1', '2026-04-09 04:53:01.343+00', '2026-04-09 04:55:11.843597+00');
INSERT INTO public.beach_day_recommendations VALUES ('huntington-dog-beach', '2026-04-12', 'caution', '2026-04-12 18:00:00+00', '2026-04-12 19:00:00+00', '11am–1pm', 'caution', 'rainy', 51, 60.6, 14.2, 3.5, 0.7, 0.3, 72.5, 'dog_party', 0, 9, 15, '["very_low_tide", "low_uv"]', '["rain_risk", "dog_party_crowds"]', '{}', '{"weight_rain": 0.25, "weight_tide": 0.3, "weight_wind": 0.2, "weight_crowd": 0.15, "nogo_wind_speed": 25, "scoring_version": "v1", "caution_wind_speed": 15, "nogo_precip_chance": 70, "caution_tide_height": 3.5, "caution_precip_chance": 40}', 'Sunday brings excellent low tides averaging just 0.7ft, but expect a dog party scene with very crowded conditions. There''s a 42.5% chance of rain and cool 60°F temperatures with 14mph winds. Overall it''s a challenging day that requires careful timing.', 'Be prepared for potential rain and very crowded dog party conditions that could make beach management tricky.', '', 'The 11am-1pm window offers the lowest tides of the day at 0.3ft and manageable UV levels at 3.5, giving you the best beach conditions before weather potentially deteriorates.', '2026-04-13 06:00:00+00', NULL, '2026-04-12', 'America/Los_Angeles', 'v1', '2026-04-09 05:24:50.484+00', '2026-04-09 05:26:01.31725+00');
INSERT INTO public.beach_day_recommendations VALUES ('huntington-dog-beach', '2026-04-16', 'go', '2026-04-16 22:00:00+00', '2026-04-16 23:00:00+00', '3pm–5pm', 'go', 'cloudy', 3, 65.1, 12.1, 5.6, 0.6, 0.5, 50, 'moderate', 8, 5, 11, '["very_low_tide", "clear_skies", "perfect_temp", "low_tide"]', '[]', '{}', '{"weight_rain": 0.25, "weight_tide": 0.3, "weight_wind": 0.2, "weight_crowd": 0.15, "nogo_wind_speed": 25, "scoring_version": "v1", "caution_wind_speed": 15, "nogo_precip_chance": 70, "caution_tide_height": 3.5, "caution_precip_chance": 40}', 'Solid day with tides hitting 0.5ft around 3pm - that''s prime territory for maximum beach space and easier water entry for the pups. Overcast skies keep it comfortable at 65°F without the harsh sun, and being a Thursday means you''ll dodge the weekend chaos. Wind''s manageable at 12mph, though it picks up slightly in the early afternoon before calming down.', '', '', '3pm to 5pm hits the sweet spot with the lowest tide of 0.5ft giving you tons of room to roam, plus wind dies down to 11mph by 4pm making it perfect for smaller dogs.', '2026-04-17 06:00:00+00', NULL, '2026-04-16', 'America/Los_Angeles', 'v1', '2026-04-14 08:02:04.057+00', '2026-04-14 08:03:53.399926+00');
INSERT INTO public.beach_day_recommendations VALUES ('huntington-dog-beach', '2026-04-14', 'go', '2026-04-14 21:00:00+00', '2026-04-14 22:00:00+00', '2pm–4pm', 'go', 'sunny', 0, 67.3, 9.7, 7.1, 0.2, 0, 35, 'moderate', 9, 4, 11, '["very_low_tide", "clear_skies", "perfect_temp"]', '[]', '{}', '{"weight_rain": 0.25, "weight_tide": 0.3, "weight_wind": 0.2, "weight_crowd": 0.15, "nogo_wind_speed": 25, "scoring_version": "v1", "caution_wind_speed": 15, "nogo_precip_chance": 70, "caution_tide_height": 3.5, "caution_precip_chance": 40}', 'Perfect Tuesday with super low tides hitting 0ft around 2pm - that''s when you get the most beach real estate for your pup to run. Clear skies and 67°F temps make it comfortable for both of you, just pack sunscreen with UV at 7. Crowds stay moderate since it''s a weekday, and those light 10mph winds keep things pleasant.', '', '', 'That 2-4pm slot gives you the absolute lowest tide at 0ft, so maximum beach space before it starts rising again.', '2026-04-15 06:00:00+00', NULL, '2026-04-14', 'America/Los_Angeles', 'v1', '2026-04-14 08:02:04.057+00', '2026-04-14 08:03:53.399926+00');
INSERT INTO public.beach_day_recommendations VALUES ('del-mar-dog-beach', '2026-04-08', 'go', '2026-04-08 15:00:00+00', '2026-04-08 17:00:00+00', '8am–11am', 'go', 'foggy', 45, 65.1, 2, 2.4, NULL, NULL, 20, 'quiet', 13, 0, 11, '["clear_skies", "calm_wind", "quiet_beach", "low_uv", "perfect_temp"]', '[]', '{}', '{"weight_rain": 0.25, "weight_tide": 0.3, "weight_wind": 0.2, "weight_crowd": 0.15, "nogo_wind_speed": 25, "scoring_version": "v1", "caution_wind_speed": 15, "nogo_precip_chance": 70, "caution_tide_height": 3.5, "caution_precip_chance": 40}', 'Wednesday looks fantastic with clear skies, calm 2mph winds, and a comfortable 65°F temperature. The beach will be quiet with low UV levels at 2.4, making it ideal for extended play sessions. Perfect conditions for a relaxing morning with your pup.', '', '', 'The 8am-11am window offers the best combination of calm 2mph winds, perfect 65°F temps, and quiet beach conditions before crowds potentially build later in the day.', '2026-04-09 06:00:00+00', NULL, '2026-04-08', 'America/Los_Angeles', 'v1', '2026-04-09 04:53:01.343+00', '2026-04-09 04:55:11.843597+00');
INSERT INTO public.beach_day_recommendations VALUES ('huntington-dog-beach', '2026-04-18', 'go', '2026-04-18 14:00:00+00', '2026-04-18 15:00:00+00', '7am–9am', 'go', 'cloudy', 3, 63.5, 2.1, 0.5, 1.2, 0.6, 22.5, 'quiet', 5, 4, 15, '["low_tide", "clear_skies", "calm_wind", "quiet_beach", "low_uv"]', '[]', '{}', '{"weight_rain": 0.25, "weight_tide": 0.3, "weight_wind": 0.2, "weight_crowd": 0.15, "nogo_wind_speed": 25, "scoring_version": "v1", "caution_wind_speed": 15, "nogo_precip_chance": 70, "caution_tide_height": 3.5, "caution_precip_chance": 40}', 'Perfect low tide morning with the tide starting at 0.6ft and rising to 1.9ft by 8am. Overcast skies keep things cool at 63-64°F with barely any wind, so your pup won''t overheat. It''s a Saturday so expect more folks to roll in after 9am, but early birds get the best conditions. After that window closes, conditions get rough for most of the day.', '', '', 'That 7-9am window hits the sweet spot with the lowest tide of the day and practically zero wind before the weekend crowd shows up.', '2026-04-19 06:00:00+00', NULL, '2026-04-18', 'America/Los_Angeles', 'v1', '2026-04-14 08:02:04.057+00', '2026-04-14 08:03:53.399926+00');
