INSERT INTO public.beach_day_recommendations VALUES ('huntington-dog-beach', '2026-04-13', 'go', '2026-04-13 14:00:00+00', '2026-04-13 15:00:00+00', '7am–9am', 'go', 'cloudy', 3, 55, 2.4, 0.2, NULL, NULL, 15, 'quiet', 13, 0, 11, '["clear_skies", "calm_wind", "quiet_beach", "low_uv"]', '[]', '{}', '{"weight_rain": 0.25, "weight_tide": 0.3, "weight_wind": 0.2, "weight_crowd": 0.15, "nogo_wind_speed": 25, "scoring_version": "v1", "caution_wind_speed": 15, "nogo_precip_chance": 70, "caution_tide_height": 3.5, "caution_precip_chance": 40}', 'Monday''s looking solid with calm 2mph winds and clear skies - perfect conditions for the pups to run around without getting sandblasted. The beach will be quiet since it''s a weekday, so your dog can actually play fetch without dodging crowds. Temps are a bit chilly at 55°F, so I''d throw on a hoodie for the early morning session. With 13 hours of good conditions, you''ve got plenty of flexibility to hit the sand whenever works.', '', '', 'That 7-9am slot is prime time with the calmest winds at 2.4mph and practically zero UV, plus the beach is dead quiet before the day crowd shows up.', '2026-04-14 06:00:00+00', NULL, '2026-04-13', 'America/Los_Angeles', 'v1', '2026-04-14 04:15:17.224+00', '2026-04-14 04:16:24.773556+00');
