INSERT INTO public.beach_day_recommendations VALUES ('coronado-dog-beach', '2026-04-15', 'go', '2026-04-15 21:00:00+00', '2026-04-15 22:00:00+00', '2pm–4pm', 'go', 'cloudy', 3, 67.9, 11.3, 7.2, 0.3, 0.2, 30, 'quiet', 8, 5, 11, '["very_low_tide", "clear_skies", "quiet_beach", "perfect_temp"]', '[]', '{}', '{"weight_rain": 0.25, "weight_tide": 0.3, "weight_wind": 0.2, "weight_crowd": 0.15, "nogo_wind_speed": 25, "scoring_version": "v1", "caution_wind_speed": 15, "nogo_precip_chance": 70, "caution_tide_height": 3.5, "caution_precip_chance": 40}', 'This is looking like a solid day with a super low 0.3ft tide giving the dogs tons of room to run around. Clear skies and 68°F temps are perfect - not too hot, not too cold. It''s going to be pretty quiet out there too, so your pup can really stretch their legs. Just throw on some sunscreen since the UV is hitting 7.', '', '', 'The 2pm-4pm window hits the sweet spot with the lowest tide at 0.2ft and light 11mph winds, plus you''ll have the beach mostly to yourselves.', '2026-04-16 06:00:00+00', NULL, '2026-04-15', 'America/Los_Angeles', 'v1', '2026-04-14 04:15:17.224+00', '2026-04-14 04:17:33.444739+00');
