INSERT INTO public.beach_day_recommendations VALUES ('coronado-dog-beach', '2026-04-17', 'go', '2026-04-17 14:00:00+00', '2026-04-17 15:00:00+00', '7am–9am', 'go', 'sunny', 0, 60.8, 1.5, 0.6, 2.8, 2.1, 12.5, 'quiet', 8, 5, 11, '["clear_skies", "calm_wind", "quiet_beach", "low_uv"]', '[]', '{}', '{"weight_rain": 0.25, "weight_tide": 0.3, "weight_wind": 0.2, "weight_crowd": 0.15, "nogo_wind_speed": 25, "scoring_version": "v1", "caution_wind_speed": 15, "nogo_precip_chance": 70, "caution_tide_height": 3.5, "caution_precip_chance": 40}', 'Perfect morning setup with 2.8ft average tide and dead calm 1.5mph winds - your pup will have plenty of room to run on the exposed sand. It''s quiet out there early, around 60°F so bring a hoodie for yourself but the dogs won''t mind. Clear skies and low UV means you can stay out longer without worrying about burning.', '', '', '7-9am is money - tide''s at its lowest around 2.1ft giving you maximum beach real estate, and winds are basically nonexistent before they pick up later.', '2026-04-18 06:00:00+00', NULL, '2026-04-17', 'America/Los_Angeles', 'v1', '2026-04-14 04:15:17.224+00', '2026-04-14 04:17:33.444739+00');
INSERT INTO public.beach_day_recommendations VALUES ('coronado-dog-beach', '2026-04-18', 'go', '2026-04-18 14:00:00+00', '2026-04-18 15:00:00+00', '7am–9am', 'go', 'cloudy', 3, 63.6, 4.2, 0.5, 1.4, 0.7, 17.5, 'quiet', 3, 6, 15, '["low_tide", "clear_skies", "calm_wind", "quiet_beach", "low_uv"]', '[]', '{}', '{"weight_rain": 0.25, "weight_tide": 0.3, "weight_wind": 0.2, "weight_crowd": 0.15, "nogo_wind_speed": 25, "scoring_version": "v1", "caution_wind_speed": 15, "nogo_precip_chance": 70, "caution_tide_height": 3.5, "caution_precip_chance": 40}', 'Looks like a solid morning with that 1.4ft tide giving the pups tons of beach to run on. Winds are staying calm at 4mph and it''s clear skies, so no weather drama. Only catch is the afternoon and evening get dicey - probably rough surf or crowds picking up. I''d definitely hit it early since you''ve only got a couple good hours.', '', '', 'That 7-9am window hits the sweet spot with the lowest tide at 0.7ft and practically no wind, plus you''ll have the beach mostly to yourselves.', '2026-04-19 06:00:00+00', NULL, '2026-04-18', 'America/Los_Angeles', 'v1', '2026-04-14 04:15:17.224+00', '2026-04-14 04:17:33.444739+00');
