INSERT INTO public.scoring_config VALUES ('7677ca07-616d-4caf-9efc-3b451a8e5116', 'v1', '2026-01-01', 'Initial scoring configuration for Dog Beach Scout. Tide weighted highest (30%) — low tide is the primary visit driver. Rain second (25%) — overcast/drizzle is a strong deterrent with dogs. Wind third (20%). Crowd fourth (15%). Temp and UV cosmetic (5% each).', true, 70, 25, '{95,96,97,98,99,63,64,65,66,67,71,72,73,74,75,76,77}', 40, 15, 3.5, 8, 1.0, 0.5, 15, 8, 65, 80, 4, 30, 60, 80, 0.30, 0.25, 0.20, 0.15, 0.05, 0.05, 4.0, 25, 72, 30, 11, 2, 5, 5.0, '2026-04-09 02:15:19.161916+00', '2026-04-09 02:15:19.161916+00');
